1	const BASE_PREMIUM = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	} as const;
9	
10	export type ItemType = keyof typeof BASE_PREMIUM;
11	
12	export type Item = { type: ItemType; cursed?: boolean; enchantment?: number };
13	
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
17	const LOYALTY_YEARS_THRESHOLD = 2;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	
20	function itemSurcharge(item: Item): number {
21	  const base = BASE_PREMIUM[item.type];
22	  let surcharge = 0;
23	  if (item.cursed) {
24	    surcharge += base * 0.5;
25	  }
26	  if (item.enchantment !== undefined && item.enchantment >= 5) {
27	    surcharge += base * 0.3;
28	  }
29	  return surcharge;
30	}
31	
32	export function calculatePremium(items: Item[], customer?: { yearsWithMHPCO: number }): number {
33	  const groups = new Map<ItemType, number>();
34	  let totalSurcharge = 0;
35	  for (const item of items) {
36	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
37	    totalSurcharge += itemSurcharge(item);
38	  }
39	
40	  let total = 0;
41	  for (const [type, count] of groups) {
42	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
43	      total += BLOCK_PREMIUM;
44	    } else {
45	      total += count * BASE_PREMIUM[type];
46	    }
47	  }
48	  let policyPremium = total + totalSurcharge;
49	  if (customer && customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
50	    policyPremium *= 1 - LOYALTY_DISCOUNT_RATE;
51	  }
52	  return policyPremium;
53	}
